# Linux Security Hardening Auditor
import subprocess
import os
import re

class HardeningAuditor:
    def __init__(self):
        self.findings = []

    def check_ssh_config(self):
        """Audit SSH configuration for security best practices."""
        config_path = '/etc/ssh/sshd_config'
        issues = []

        required_settings = {
            'PermitRootLogin': 'no',
            'PasswordAuthentication': 'no',
            'X11Forwarding': 'no',
            'Protocol': '2',
            'MaxAuthTries': '3',
        }

        try:
            with open(config_path, 'r') as f:
                config = f.read()

            for setting, expected in required_settings.items():
                pattern = rf'^\s*{setting}\s+(\S+)'
                match = re.search(pattern, config, re.MULTILINE)
                if not match:
                    issues.append(f"MISSING: {setting} not configured")
                elif match.group(1).lower() != expected.lower():
                    issues.append(f"WRONG: {setting} = {match.group(1)} (should be {expected})")
        except FileNotFoundError:
            issues.append("SSH config not found")

        return issues

    def check_firewall(self):
        """Check if firewall is active."""
        try:
            result = subprocess.run(['iptables', '-L', '-n'], capture_output=True, text=True)
            rules = result.stdout.strip().split('\n')
            if len(rules) <= 3:
                return ["WARNING: No iptables rules configured"]
            return []
        except FileNotFoundError:
            return ["WARNING: iptables not found"]

    def check_updates(self):
        """Check for pending security updates."""
        try:
            result = subprocess.run(['apt', 'list', '--upgradable'], capture_output=True, text=True)
            upgradable = [l for l in result.stdout.split('\n') if 'upgradable' in l.lower()]
            if upgradable:
                return [f"UPDATE AVAILABLE: {len(upgradable)} packages"]
            return []
        except FileNotFoundError:
            return []

    def check_users(self):
        """Check for users with empty passwords or UID 0."""
        issues = []
        try:
            with open('/etc/passwd', 'r') as f:
                for line in f:
                    parts = line.strip().split(':')
                    if len(parts) >= 7:
                        uid = int(parts[2])
                        shell = parts[6]
                        if uid == 0 and parts[0] != 'root':
                            issues.append(f"ROOT USER: {parts[0]} has UID 0")
                        if shell in ['/bin/bash', '/bin/sh'] and uid >= 1000:
                            issues.append(f"SHELL ACCESS: {parts[0]} has interactive shell")
        except FileNotFoundError:
            pass
        return issues

    def run_full_audit(self):
        """Run complete hardening audit."""
        checks = {
            'SSH': self.check_ssh_config(),
            'Firewall': self.check_firewall(),
            'Updates': self.check_updates(),
            'Users': self.check_users()
        }
        for category, issues in checks.items():
            if issues:
                print(f"\n[{category}]")
                for issue in issues:
                    print(f"  - {issue}")
